class Solution:
    def satisfiesConditions(self, grid) -> bool:
        m, n = len(grid), len(grid[0])
        for i in range(m):
            for j in range(n):
                if i + 1 < m and grid[i][j] != grid[i+1][j]:
                    return False
                if j + 1 < n and grid[i][j] == grid[i][j+1]:
                    return False
        return True

